const http = require('http');
const input = $input.first().json;
const prompt = input.body?.prompt || input.prompt || '';
if (!prompt) return [{ json: { error: 'Missing prompt field in request body', parsed: null } }];
const litellmHost = input.litellmHost;
const litellmPort = parseInt(input.litellmPort, 10);
const litellmApiKey = input.litellmApiKey || '';
const systemPrompt = `You are a JSON parser for OpenShift operations. Given a user request, extract the intent and parameters.
Return ONLY valid JSON with this structure:
{
  "action": "createDeployment" | "listPods" | "listResources" | "getResource" | "deleteResource" | "scaleDeployment" | "getPodLogs" | "listProjects" | "monitorDeployments" | "podTop" | "nodeTop",
  "params": { ...action-specific parameters... }
}

Action parameter schemas:
- createDeployment: {name, image, namespace, replicasStr, cpuRequest?, memoryRequest?, cpuLimit?, memoryLimit?, containerPortStr?}
- listPods: {namespace}
- listResources: {resource_type, namespace?}
- getResource: {resource_type, name, namespace?}
- deleteResource: {resource_type, name, namespace}
- scaleDeployment: {name, namespace, replicas}
- getPodLogs: {name, namespace, tail_lines?}
- listProjects: {}
- monitorDeployments: {namespace}
- podTop: {namespace}
- nodeTop: {}

Examples:
User: "Create a deployment called httpd-test in namespace n8n-test using image registry/httpd:latest with 2 replicas"
{"action":"createDeployment","params":{"name":"httpd-test","image":"registry/httpd:latest","namespace":"n8n-test","replicasStr":"2","cpuRequest":"50m","memoryRequest":"64Mi","cpuLimit":"200m","memoryLimit":"256Mi","containerPortStr":"8080"}}

User: "List pods in namespace openshift-lightspeed"
{"action":"listPods","params":{"namespace":"openshift-lightspeed"}}

User: "Scale deployment myapp in namespace test to 5 replicas"
{"action":"scaleDeployment","params":{"name":"myapp","namespace":"test","replicas":"5"}}

User: "Delete deployment httpd-test in namespace n8n-test"
{"action":"deleteResource","params":{"resource_type":"deployment","name":"httpd-test","namespace":"n8n-test"}}

Return ONLY the JSON, no markdown, no explanation.`;
const requestBody = JSON.stringify({
  model: 'llama-scout-17b',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: prompt }
  ],
  temperature: 0.1,
  max_tokens: 512
});
return new Promise((resolve, reject) => {
  const req = http.request({
    hostname: litellmHost, port: litellmPort, path: '/v1/chat/completions', method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + litellmApiKey, 'Content-Length': Buffer.byteLength(requestBody) }
  }, (res) => {
    let data = '';
    res.on('data', (chunk) => { data += chunk; });
    res.on('end', () => {
      try {
        const resp = JSON.parse(data);
        let content = resp.choices?.[0]?.message?.content || '';
        content = content.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
        content = content.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
        const parsed = JSON.parse(content);
        resolve([{ json: { ...input, userPrompt: prompt, parsed, parseError: null } }]);
      } catch (e) {
        resolve([{ json: { ...input, userPrompt: prompt, parsed: null, parseError: 'Failed to parse LLM response: ' + e.message } }]);
      }
    });
  });
  req.on('error', (e) => { resolve([{ json: { ...input, userPrompt: prompt, parsed: null, parseError: 'LiteLLM unreachable: ' + e.message } }]); });
  req.write(requestBody);
  req.end();
});

const http = require('http');
const input = $input.first().json;
if (input.parseError || !input.parsed) {
  return [{ json: { ...input, mcpResult: null, mcpError: input.parseError || 'No parsed intent' } }];
}
const action = input.parsed.action;
const params = input.parsed.params;

const toolMap = {
  createDeployment: { host: 'mcpHost', port: 'mcpPort', tool: 'createDeployment', args: (p) => ({
    name: p.name, image: p.image, namespace: p.namespace,
    replicasStr: p.replicasStr || '1', cpuRequest: p.cpuRequest || '50m',
    memoryRequest: p.memoryRequest || '64Mi', cpuLimit: p.cpuLimit || '200m',
    memoryLimit: p.memoryLimit || '256Mi', containerPortStr: p.containerPortStr || '8080'
  })},
  listPods: { host: 'k8sMcpHost', port: 'k8sMcpPort', tool: 'pods_list_in_namespace', args: (p) => ({ namespace: p.namespace }) },
  listResources: { host: 'k8sMcpHost', port: 'k8sMcpPort', tool: 'resources_list', args: (p) => ({ resource_type: p.resource_type, namespace: p.namespace || '' }) },
  getResource: { host: 'k8sMcpHost', port: 'k8sMcpPort', tool: 'resources_get', args: (p) => ({ resource_type: p.resource_type, name: p.name, namespace: p.namespace || '' }) },
  deleteResource: { host: 'k8sMcpHost', port: 'k8sMcpPort', tool: 'resources_delete', args: (p) => ({ resource_type: p.resource_type, name: p.name, namespace: p.namespace }) },
  scaleDeployment: { host: 'k8sMcpHost', port: 'k8sMcpPort', tool: 'resources_scale', args: (p) => ({ resource_type: 'deployment', name: p.name, namespace: p.namespace, replicas: parseInt(p.replicas, 10) }) },
  getPodLogs: { host: 'k8sMcpHost', port: 'k8sMcpPort', tool: 'pods_log', args: (p) => ({ name: p.name, namespace: p.namespace, tail_lines: parseInt(p.tail_lines || '50', 10) }) },
  listProjects: { host: 'mcpHost', port: 'mcpPort', tool: 'listProjects', args: () => ({}) },
  monitorDeployments: { host: 'mcpHost', port: 'mcpPort', tool: 'monitorDeployments', args: (p) => ({ namespace: p.namespace }) },
  podTop: { host: 'k8sMcpHost', port: 'k8sMcpPort', tool: 'pods_top', args: (p) => ({ namespace: p.namespace }) },
  nodeTop: { host: 'k8sMcpHost', port: 'k8sMcpPort', tool: 'nodes_top', args: () => ({}) }
};

const mapping = toolMap[action];
if (!mapping) {
  return [{ json: { ...input, mcpResult: null, mcpError: 'Unknown action: ' + action } }];
}

const mcpHost = input[mapping.host];
const mcpPort = parseInt(input[mapping.port], 10);
const toolName = mapping.tool;
const toolArgs = mapping.args(params);

function mcpRequest(host, port, body, sessionId) {
  return new Promise((resolve, reject) => {
    const data = JSON.stringify(body);
    const headers = { 'Content-Type': 'application/json', 'Accept': 'application/json, text/event-stream', 'Content-Length': Buffer.byteLength(data) };
    if (sessionId) headers['Mcp-Session-Id'] = sessionId;
    const req = http.request({ hostname: host, port, path: '/mcp', method: 'POST', headers }, (res) => {
      let body = '';
      res.on('data', (chunk) => body += chunk);
      res.on('end', () => {
        const lines = body.split('\n');
        let jsonData = '';
        for (const line of lines) { if (line.startsWith('data: ')) jsonData = line.substring(6); }
        resolve({ status: res.statusCode, headers: res.headers, body: jsonData || body });
      });
    });
    req.on('error', reject);
    req.write(data);
    req.end();
  });
}

try {
  const init = await mcpRequest(mcpHost, mcpPort, { jsonrpc: '2.0', id: 1, method: 'initialize', params: { protocolVersion: '2024-11-05', capabilities: {}, clientInfo: { name: 'n8n-agent', version: '1.0' } } });
  const sid = init.headers['mcp-session-id'];
  await mcpRequest(mcpHost, mcpPort, { jsonrpc: '2.0', method: 'notifications/initialized' }, sid);
  const result = await mcpRequest(mcpHost, mcpPort, { jsonrpc: '2.0', id: 3, method: 'tools/call', params: { name: toolName, arguments: toolArgs } }, sid);
  const parsed = JSON.parse(result.body);
  const mcpResult = parsed.result?.content?.[0]?.text || JSON.stringify(parsed.error || parsed);
  return [{ json: { ...input, mcpResult, mcpError: null, mcpTool: toolName, mcpArgs: toolArgs } }];
} catch (e) {
  return [{ json: { ...input, mcpResult: null, mcpError: 'MCP call failed: ' + e.message, mcpTool: toolName } }];
}

const http = require('http');
const input = $input.first().json;
const mcpResult = input.mcpResult || input.mcpError || 'No result';
const truncated = mcpResult.length > 2000 ? mcpResult.substring(0, 2000) + '\n[... truncated]' : mcpResult;
const action = input.parsed?.action || 'unknown';
const litellmHost = input.litellmHost;
const litellmPort = parseInt(input.litellmPort, 10);
const litellmApiKey = input.litellmApiKey || '';
const systemPrompt = 'You are a helpful OpenShift assistant. The user asked: "' + (input.userPrompt || '') + '". The action "' + action + '" was executed via MCP tool "' + (input.mcpTool || '') + '". Below is the result. Provide a clear, concise summary of what happened. If it was a creation, confirm what was created. If it was a listing, summarize the key data. Be direct and helpful.';
const requestBody = JSON.stringify({
  model: 'llama-scout-17b',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: truncated }
  ],
  temperature: 0.3,
  max_tokens: 1024
});
return new Promise((resolve, reject) => {
  const req = http.request({
    hostname: litellmHost, port: litellmPort, path: '/v1/chat/completions', method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + litellmApiKey, 'Content-Length': Buffer.byteLength(requestBody) }
  }, (res) => {
    let data = '';
    res.on('data', (chunk) => { data += chunk; });
    res.on('end', () => {
      try {
        const parsed = JSON.parse(data);
        let answer = parsed.choices?.[0]?.message?.content || 'Could not generate summary';
        answer = answer.replace(/<think>[\s\S]*?<\/think>/g, '').trim();
        resolve([{ json: { ...input, answer } }]);
      } catch (e) {
        resolve([{ json: { ...input, answer: 'Result: ' + truncated } }]);
      }
    });
  });
  req.on('error', (e) => { resolve([{ json: { ...input, answer: 'Result: ' + truncated } }]); });
  req.write(requestBody);
  req.end();
});
